const results = $.steps.webSearch.response.results || [];
const domain = $.input.knowledgeDomain || 'general';

let sourcesText = '';
results.forEach((r, i) => {
  sourcesText += (i + 1) + '. ' + (r.title || 'Untitled') + '\n';
  sourcesText += '   URL: ' + r.url + '\n';
  if (r.publishedDate) sourcesText += '   Published: ' + r.publishedDate + '\n';
  sourcesText += '   ' + (r.text || '').slice(0, 1200) + '\n\n';
});

return { sourcesText, sourceCount: results.length, domain, topSources: results.slice(0, 5).map(r => ({ title: r.title || r.url, url: r.url })) };

const d = $.steps.compileSources.output;
const question = $.input.question;
const domain = d.domain;

let prompt = 'You are a knowledgeable expert in ' + domain + '. Answer the following question using the research sources provided. Act as a helpful knowledge assistant with deep domain expertise.\n\n';
prompt += 'QUESTION: ' + question + '\n';
prompt += 'DOMAIN: ' + domain + '\n\n';
prompt += 'KNOWLEDGE SOURCES (' + d.sourceCount + ' found):\n';
prompt += d.sourcesText + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Provide a thorough, expert-level answer synthesized from the sources\n';
prompt += '- Cite sources by number, e.g. [1], [2]\n';
prompt += '- If sources conflict, explain the different perspectives\n';
prompt += '- Include practical takeaways or recommendations when appropriate\n';
prompt += '- Use Slack mrkdwn: *bold*, _italic_, > for quotes, numbered lists\n';
prompt += '- Slack rules: use *bold* (NOT **bold**). No markdown tables. No # headings.\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "answer": "<comprehensive expert answer in Slack mrkdwn>",\n';
prompt += '  "confidence": "high|medium|low",\n';
prompt += '  "keyInsights": ["<insight1>", "<insight2>", "<insight3>"],\n';
prompt += '  "relatedTopics": ["<topic1>", "<topic2>"],\n';
prompt += '  "sourcesUsed": [1, 2, 3]\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { answer: raw, confidence: 'medium', keyInsights: [], relatedTopics: [], sourcesUsed: [] }; }

const ai = $.steps.parseAI.output;
const question = $.input.question;
const sourceCount = $.steps.compileSources.output.sourceCount;
const topSources = $.steps.compileSources.output.topSources || [];

const confidenceEmoji = ai.confidence === 'high' ? ':large_green_circle:' : ai.confidence === 'low' ? ':red_circle:' : ':large_yellow_circle:';

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'AI Knowledge Assistant' } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Question:* ' + question } });
blocks.push({ type: 'divider' });

const answerText = (ai.answer || 'No answer generated.').slice(0, 2900);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: answerText } });
blocks.push({ type: 'divider' });

if (ai.keyInsights && ai.keyInsights.length > 0) {
  let insText = '*Key Insights:*\n';
  ai.keyInsights.forEach((ins, i) => { insText += (i + 1) + '. ' + ins + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: insText.slice(0, 1800) } });
}

if (ai.relatedTopics && ai.relatedTopics.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Related Topics:* ' + ai.relatedTopics.join(', ') } });
}

blocks.push({ type: 'divider' });

let sourceLinks = '';
topSources.slice(0, 3).forEach((s, i) => {
  sourceLinks += (i + 1) + '. <' + s.url + '|' + (s.title || s.url).slice(0, 60) + '>\n';
});
if (sourceLinks) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Top Sources:*\n' + sourceLinks } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: confidenceEmoji + ' Confidence: *' + (ai.confidence || 'medium') + '* | Sources analyzed: *' + sourceCount + '*' }] });

const fallback = 'AI Knowledge answer: ' + question;
return { blocks, fallback };
